solution: class Solution {
public:
    long long minimumSteps(string s) {
        long long res = 0;
        int zeros = 0;
        for (int i = 0; i < s.size(); ++i) {
            if (s[i] == '0') {
                res += i - zeros;
                ++zeros;
            }
        }
        return res;
    }
};
